<template><el-card><template #header>企业微信配置</template><el-alert title="Secret 与 Webhook 将加密保存，页面不会回显完整值。" type="info" :closable="false"/><el-form label-width="150px" style="max-width:720px;margin-top:20px"><el-form-item label="企业 CorpId"><el-input v-model="form.corpId"/></el-form-item><el-form-item label="通讯录 Secret"><el-input v-model="form.directorySecret" type="password" show-password placeholder="留空表示不修改"/></el-form-item><el-form-item label="应用 AgentId"><el-input-number v-model="form.agentId"/></el-form-item><el-form-item label="应用 Secret"><el-input v-model="form.appSecret" type="password" show-password placeholder="留空表示不修改"/></el-form-item><el-form-item><el-button type="primary" @click="save">保存</el-button><el-button @click="verify">验证配置</el-button><el-button type="success" @click="sync">同步组织架构</el-button></el-form-item></el-form><el-divider>最近同步</el-divider><el-table :data="logs"><el-table-column prop="startedAt" label="开始时间"/><el-table-column prop="status" label="状态"/><el-table-column prop="departmentCount" label="部门"/><el-table-column prop="personCount" label="人员"/><el-table-column prop="errorDetail" label="错误"/></el-table><el-divider>国家工作日日历</el-divider><el-alert v-if="!calendars.some((x:any)=>x.yearValue===new Date().getFullYear())" title="当前年度工作日日历缺失，工作日任务将跳过并告警" type="error" :closable="false"/><el-table :data="calendars"><el-table-column prop="yearValue" label="年份"/><el-table-column prop="status" label="状态"/><el-table-column prop="sourceDocument" label="国务院通知"/><el-table-column prop="versionValue" label="版本"/><el-table-column prop="importedAt" label="更新时间"/></el-table></el-card></template><script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{ElMessage}from'element-plus';import{getWecomSettings,saveWecomSettings,verifyWecomSettings,syncWecom,listSyncLogs,getWorkdayCalendar}from'@/api';const form=reactive<any>({corpId:'',directorySecret:'',agentId:null,appSecret:''}),logs=ref<any[]>([]),calendars=ref<any[]>([]);async function load(){const[r,l,c]=await Promise.all([getWecomSettings(),listSyncLogs(),getWorkdayCalendar()]);Object.assign(form,r.data.data);logs.value=l.data.data;calendars.value=c.data.data}async function save(){await saveWecomSettings(form);ElMessage.success('已保存')}async function verify(){await verifyWecomSettings();ElMessage.success('配置有效')}async function sync(){const r=await syncWecom();ElMessage.success(`同步完成：${r.data.data.persons} 人`);load()}onMounted(load)</script>